import React, { useState, useEffect } from 'react';
import { BrowserRouter as Router, Route, Redirect } from 'react-router-dom';

const clientId = 'YOUR_CLIENT_ID';
const redirectUri = 'YOUR_REDIRECT_URI';
const authEndpoint = 'https://authorization-server.com/auth';
const tokenEndpoint = 'https://authorization-server.com/token';

const App = () => {
  const [token, setToken] = useState(localStorage.getItem('access_token'));

  useEffect(() => {
    const urlParams = new URLSearchParams(window.location.search);
    const code = urlParams.get('code');

    if (code && !token) {
      fetchToken(code);
    }
  }, [token]);

  const fetchToken = async (code) => {
    try {
      const response = await fetch(tokenEndpoint, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/x-www-form-urlencoded',
        },
        body: new URLSearchParams({
          grant_type: 'authorization_code',
          code,
          redirect_uri: redirectUri,
          client_id: clientId,
        }),
      });

      const data = await response.json();
      if (data.access_token) {
        localStorage.setItem('access_token', data.access_token);
        setToken(data.access_token);
      }
    } catch (error) {
      console.error('Error fetching token:', error);
    }
  };

  const login = () => {
    window.location.href = `${authEndpoint}?response_type=code&client_id=${clientId}&redirect_uri=${encodeURIComponent(redirectUri)}`;
  };

  return (
    <Router>
      <Route path="/" exact>
        {token ? <Redirect to="/dashboard" /> : <button onClick={login}>Login with OAuth</button>}
      </Route>
      <Route path="/dashboard">
        {token ? <Dashboard token={token} /> : <Redirect to="/" />}
      </Route>
    </Router>
  );
};

const Dashboard = ({ token }) => {
  const [data, setData] = useState(null);

  useEffect(() => {
    const fetchData = async () => {
      try {
        const response = await fetch('https://api-server.com/data', {
          headers: {
            Authorization: `Bearer ${token}`,
          },
        });
        const result = await response.json();
        setData(result);
      } catch (error) {
        console.error('Error fetching data:', error);
      }
    };

    fetchData();
  }, [token]);

  return <div>{data ? JSON.stringify(data) : 'Loading...'}</div>;
};

export default App;